<template>
  <div class="wuxia-game">
    <!-- 游戏标题 -->
    <header class="game-header">
      <div class="header-content">
        <h1>
          <span class="chinese-title">江湖风云录</span>
          <span class="english-title">Wuxia Chronicles</span>
        </h1>
        <p class="subtitle">仗剑天涯，快意恩仇，你的武侠传奇由此开始</p>
        <div class="header-stats">
          <div class="stat-badge">
            <span class="badge-icon">⚔️</span>
            <span class="badge-text">等级: {{ player.level }}</span>
          </div>
          <div class="stat-badge">
            <span class="badge-icon">💰</span>
            <span class="badge-text">{{ player.money }} 两</span>
          </div>
          <div class="stat-badge">
            <span class="badge-icon">✨</span>
            <span class="badge-text">{{ player.xp }} 修为</span>
          </div>
          <div class="stat-badge">
            <span class="badge-icon">📍</span>
            <span class="badge-text">{{ currentLocation.name }}</span>
          </div>
        </div>
      </div>
    </header>

    <div class="game-container">
      <!-- 左侧玩家信息面板 -->
      <div class="left-panel">
        <!-- 玩家头像和基本信息 -->
        <div class="player-card">
          <div class="player-header">
            <div class="avatar-container">
              <div class="avatar-icon" :class="player.class">
                <div class="avatar-inner"></div>
              </div>
              <div class="level-badge">Lv.{{ player.level }}</div>
            </div>
            <div class="player-info">
              <h3 class="player-name">{{ player.name }}</h3>
              <div class="player-title">{{ player.className }}</div>
              <div class="xp-bar">
                <div class="xp-label">修为进度</div>
                <div class="xp-progress">
                  <div class="xp-fill" :style="{width: xpPercent + '%'}"></div>
                </div>
                <div class="xp-text">{{ player.xp }}/{{ xpToNextLevel }}</div>
              </div>
            </div>
          </div>
          
          <!-- 属性数值 -->
          <div class="attributes-grid">
            <div class="attribute">
              <div class="attr-icon">❤️</div>
              <div class="attr-info">
                <div class="attr-name">生命</div>
                <div class="attr-value">{{ player.hp }}/{{ player.maxHp }}</div>
              </div>
              <div class="attr-bar">
                <div class="bar-fill hp" :style="{width: playerHpPercent + '%'}"></div>
              </div>
            </div>
            <div class="attribute">
              <div class="attr-icon">💠</div>
              <div class="attr-info">
                <div class="attr-name">内力</div>
                <div class="attr-value">{{ player.mp }}/{{ player.maxMp }}</div>
              </div>
              <div class="attr-bar">
                <div class="bar-fill mp" :style="{width: playerMpPercent + '%'}"></div>
              </div>
            </div>
            <div class="attribute">
              <div class="attr-icon">⚔️</div>
              <div class="attr-info">
                <div class="attr-name">攻击</div>
                <div class="attr-value">{{ player.attack + getEquipmentAttack() }}</div>
              </div>
            </div>
            <div class="attribute">
              <div class="attr-icon">🛡️</div>
              <div class="attr-info">
                <div class="attr-name">防御</div>
                <div class="attr-value">{{ player.defense + getEquipmentDefense() }}</div>
              </div>
            </div>
            <div class="attribute">
              <div class="attr-icon">🏃</div>
              <div class="attr-info">
                <div class="attr-name">轻功</div>
                <div class="attr-value">{{ player.agility }}</div>
              </div>
            </div>
            <div class="attribute">
              <div class="attr-icon">🎯</div>
              <div class="attr-info">
                <div class="attr-name">暴击</div>
                <div class="attr-value">{{ player.critRate }}%</div>
              </div>
            </div>
          </div>
        </div>

        <!-- 装备栏 -->
        <div class="equipment-panel">
          <h3 class="panel-title">🛡️ 装备</h3>
          <div class="equipment-grid">
            <div class="equipment-slot" :class="{ equipped: player.equipment.weapon }" @click="showEquipmentModal('weapon')">
              <div class="slot-label">武器</div>
              <div class="slot-content">
                <div v-if="player.equipment.weapon" class="equipment-item">
                  <div class="item-name">{{ player.equipment.weapon.name }}</div>
                  <div class="item-stats">攻+{{ player.equipment.weapon.attack }}</div>
                </div>
                <div v-else class="empty-slot">未装备</div>
              </div>
            </div>
            <div class="equipment-slot" :class="{ equipped: player.equipment.armor }" @click="showEquipmentModal('armor')">
              <div class="slot-label">护甲</div>
              <div class="slot-content">
                <div v-if="player.equipment.armor" class="equipment-item">
                  <div class="item-name">{{ player.equipment.armor.name }}</div>
                  <div class="item-stats">防+{{ player.equipment.armor.defense }}</div>
                </div>
                <div v-else class="empty-slot">未装备</div>
              </div>
            </div>
            <div class="equipment-slot" :class="{ equipped: player.equipment.accessory }" @click="showEquipmentModal('accessory')">
              <div class="slot-label">饰品</div>
              <div class="slot-content">
                <div v-if="player.equipment.accessory" class="equipment-item">
                  <div class="item-name">{{ player.equipment.accessory.name }}</div>
                  <div class="item-stats">{{ getAccessoryEffectText() }}</div>
                </div>
                <div v-else class="empty-slot">未装备</div>
              </div>
            </div>
          </div>
        </div>

        <!-- 技能面板 -->
        <div class="skills-panel">
          <h3 class="panel-title">🗡️ 武学技能</h3>
          <div class="skills-list">
            <div 
              v-for="(skill, index) in player.skills" 
              :key="index" 
              class="skill-item"
              :class="{ 
                active: currentSkill === index,
                unavailable: skill.cost > player.mp
              }"
              @click="selectSkill(index)"
            >
              <div class="skill-header">
                <div class="skill-name">{{ skill.name }}</div>
                <div class="skill-level">Lv.{{ skill.level }}</div>
              </div>
              <div class="skill-desc">{{ skill.description }}</div>
              <div class="skill-footer">
                <div class="skill-cost">内力: {{ skill.cost }}</div>
                <div class="skill-damage">伤害: {{ calculateSkillDamage(skill) }}</div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- 中间游戏主区域 -->
      <div class="main-panel">
        <!-- 游戏状态指示器 -->
        <div class="game-state-bar">
          <div class="state-tabs">
            <button 
              class="state-tab" 
              :class="{ active: gameState === 'world' }"
              @click="switchState('world')"
            >
              🌍 江湖
            </button>
            <button 
              class="state-tab" 
              :class="{ active: gameState === 'battle' }"
              @click="switchState('battle')"
              :disabled="!currentEnemy"
            >
              ⚔️ 战斗
            </button>
            <button 
              class="state-tab" 
              :class="{ active: gameState === 'town' }"
              @click="switchState('town')"
            >
              🏘️ 城镇
            </button>
            <button 
              class="state-tab" 
              :class="{ active: gameState === 'inventory' }"
              @click="switchState('inventory')"
            >
              🎒 背包
            </button>
          </div>
          <div class="state-info">
            <span class="state-text">{{ getGameStateText() }}</span>
            <span class="location-info">📍 {{ currentLocation.name }}</span>
          </div>
        </div>

        <!-- 动态游戏区域 -->
        <div class="game-area">
          <!-- 江湖界面 -->
          <div class="world-area" v-if="gameState === 'world'">
            <div class="location-card">
              <div class="location-header">
                <h3>{{ currentLocation.name }}</h3>
                <div class="location-type">{{ currentLocation.type }}</div>
              </div>
              <div class="location-description">
                <p>{{ currentLocation.description }}</p>
              </div>
              <div class="location-features">
                <div class="feature" v-for="(feature, index) in currentLocation.features" :key="index">
                  <span class="feature-icon">{{ feature.icon }}</span>
                  <span class="feature-text">{{ feature.text }}</span>
                </div>
              </div>
            </div>

            <div class="world-actions">
              <h3>江湖行动</h3>
              <div class="action-grid">
                <button @click="explore" class="action-card" :disabled="isExploring">
                  <div class="action-icon">🔍</div>
                  <div class="action-content">
                    <div class="action-title">探索江湖</div>
                    <div class="action-desc">遭遇敌人或发现奇遇</div>
                  </div>
                  <div class="action-time" v-if="isExploring">探索中... {{ exploreTimer }}s</div>
                </button>
                
                <button @click="meditate" class="action-card" :disabled="player.hp >= player.maxHp && player.mp >= player.maxMp">
                  <div class="action-icon">🧘</div>
                  <div class="action-content">
                    <div class="action-title">打坐调息</div>
                    <div class="action-desc">恢复生命与内力</div>
                  </div>
                  <div class="action-effect">恢复30%生命与内力</div>
                </button>
                
                <button @click="visitTown" class="action-card">
                  <div class="action-icon">🏘️</div>
                  <div class="action-content">
                    <div class="action-title">前往城镇</div>
                    <div class="action-desc">购买物品或接受任务</div>
                  </div>
                </button>
                
                <button @click="train" class="action-card" :disabled="isTraining">
                  <div class="action-icon">📚</div>
                  <div class="action-content">
                    <div class="action-title">修炼武功</div>
                    <div class="action-desc">提升武学修为</div>
                  </div>
                  <div class="action-time" v-if="isTraining">修炼中... {{ trainTimer }}s</div>
                </button>
                
                <button @click="huntTreasure" class="action-card" :disabled="isHunting">
                  <div class="action-icon">🗺️</div>
                  <div class="action-content">
                    <div class="action-title">寻宝探秘</div>
                    <div class="action-desc">寻找隐藏的宝藏</div>
                  </div>
                  <div class="action-chance">成功率: {{ treasureChance }}%</div>
                </button>
                
                <button @click="challengeArena" class="action-card" v-if="currentLocation.type === '擂台'">
                  <div class="action-icon">🥊</div>
                  <div class="action-content">
                    <div class="action-title">擂台比武</div>
                    <div class="action-desc">挑战其他武林人士</div>
                  </div>
                  <div class="action-reward">胜利奖励: 100两</div>
                </button>
              </div>
            </div>
          </div>

          <!-- 战斗界面 -->
          <div class="battle-area" v-if="gameState === 'battle'">
            <div class="battle-header">
              <h2>⚔️ 战斗 - {{ currentEnemy.name }}</h2>
              <div class="enemy-type">{{ currentEnemy.type }}</div>
            </div>
            
            <div class="battle-field">
              <div class="combatant player-side">
                <div class="combatant-card">
                  <div class="combatant-avatar" :class="player.class"></div>
                  <div class="combatant-info">
                    <div class="combatant-name">{{ player.name }}</div>
                    <div class="combatant-stats">
                      <div class="combatant-stat">
                        <span class="stat-label">生命</span>
                        <div class="stat-bar">
                          <div class="bar-fill hp" :style="{width: playerHpPercent + '%'}"></div>
                        </div>
                        <span class="stat-value">{{ player.hp }}/{{ player.maxHp }}</span>
                      </div>
                      <div class="combatant-stat">
                        <span class="stat-label">内力</span>
                        <div class="stat-bar">
                          <div class="bar-fill mp" :style="{width: playerMpPercent + '%'}"></div>
                        </div>
                        <span class="stat-value">{{ player.mp }}/{{ player.maxMp }}</span>
                      </div>
                    </div>
                    <div class="combatant-status" v-if="player.status">
                      <span class="status-badge" :class="player.status.type">{{ player.status.name }}</span>
                    </div>
                  </div>
                </div>
              </div>
              
              <div class="vs-container">
                <div class="vs-text">VS</div>
                <div class="turn-indicator" :class="{ 'player-turn': isPlayerTurn, 'enemy-turn': !isPlayerTurn }">
                  {{ isPlayerTurn ? '你的回合' : '敌方回合' }}
                </div>
              </div>
              
              <div class="combatant enemy-side">
                <div class="combatant-card">
                  <div class="combatant-avatar enemy"></div>
                  <div class="combatant-info">
                    <div class="combatant-name">{{ currentEnemy.name }}</div>
                    <div class="combatant-stats">
                      <div class="combatant-stat">
                        <span class="stat-label">生命</span>
                        <div class="stat-bar">
                          <div class="bar-fill hp enemy" :style="{width: enemyHpPercent + '%'}"></div>
                        </div>
                        <span class="stat-value">{{ currentEnemy.hp }}/{{ currentEnemy.maxHp }}</span>
                      </div>
                      <div class="combatant-stat">
                        <span class="stat-label">攻击</span>
                        <span class="stat-value">{{ currentEnemy.attack }}</span>
                      </div>
                      <div class="combatant-stat">
                        <span class="stat-label">防御</span>
                        <span class="stat-value">{{ currentEnemy.defense }}</span>
                      </div>
                    </div>
                    <div class="combatant-status" v-if="currentEnemy.status">
                      <span class="status-badge" :class="currentEnemy.status.type">{{ currentEnemy.status.name }}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
            
            <div class="battle-controls">
              <div class="skills-quickbar">
                <div class="quickbar-title">快速招式</div>
                <div class="quick-skills">
                  <button 
                    v-for="(skill, index) in player.skills.slice(0, 4)" 
                    :key="index" 
                    @click="useSkill(index)"
                    :disabled="skill.cost > player.mp || !isPlayerTurn"
                    class="quick-skill"
                    :class="{ selected: currentSkill === index }"
                  >
                    <div class="quick-skill-name">{{ skill.name }}</div>
                    <div class="quick-skill-cost">{{ skill.cost }}内力</div>
                  </button>
                </div>
              </div>
              
              <div class="battle-actions">
                <button @click="useSkill(currentSkill)" class="battle-btn primary" :disabled="player.skills[currentSkill].cost > player.mp || !isPlayerTurn">
                  <span class="btn-icon">⚔️</span>
                  <span class="btn-text">使用 {{ player.skills[currentSkill].name }}</span>
                  <span class="btn-cost">{{ player.skills[currentSkill].cost }}内力</span>
                </button>
                <button @click="defend" class="battle-btn" :disabled="!isPlayerTurn">
                  <span class="btn-icon">🛡️</span>
                  <span class="btn-text">防御</span>
                </button>
                <button @click="useItem('healing')" class="battle-btn" :disabled="!isPlayerTurn || getItemCount('healing') === 0">
                  <span class="btn-icon">❤️</span>
                  <span class="btn-text">使用金疮药</span>
                  <span class="btn-count">x{{ getItemCount('healing') }}</span>
                </button>
                <button @click="fleeBattle" class="battle-btn flee">
                  <span class="btn-icon">🏃</span>
                  <span class="btn-text">轻功遁走</span>
                  <span class="btn-chance">{{ fleeChance }}%</span>
                </button>
              </div>
            </div>
          </div>

          <!-- 城镇界面 -->
          <div class="town-area" v-if="gameState === 'town'">
            <div class="town-header">
              <h2>🏘️ 襄阳城</h2>
              <div class="town-subtitle">中原重镇，武林豪杰汇聚之地</div>
            </div>
            
            <div class="town-districts">
              <div class="district-card" @click="visitDistrict('market')">
                <div class="district-icon">🛒</div>
                <div class="district-content">
                  <div class="district-name">集市</div>
                  <div class="district-desc">购买装备、药品和材料</div>
                </div>
              </div>
              
              <div class="district-card" @click="visitDistrict('quest')">
                <div class="district-icon">📜</div>
                <div class="district-content">
                  <div class="district-name">悬赏榜</div>
                  <div class="district-desc">接受赏金任务</div>
                </div>
              </div>
              
              <div class="district-card" @click="visitDistrict('inn')">
                <div class="district-icon">🍶</div>
                <div class="district-content">
                  <div class="district-name">客栈</div>
                  <div class="district-desc">恢复状态，打听消息</div>
                </div>
              </div>
              
              <div class="district-card" @click="visitDistrict('arena')">
                <div class="district-icon">🥊</div>
                <div class="district-content">
                  <div class="district-name">比武场</div>
                  <div class="district-desc">挑战各路高手</div>
                </div>
              </div>
            </div>
            
            <!-- 市场界面 -->
            <div class="market-area" v-if="currentDistrict === 'market'">
              <h3>🛒 集市 - 购买物品</h3>
              <div class="market-tabs">
                <button class="market-tab" :class="{ active: marketTab === 'potions' }" @click="marketTab = 'potions'">药品</button>
                <button class="market-tab" :class="{ active: marketTab === 'weapons' }" @click="marketTab = 'weapons'">武器</button>
                <button class="market-tab" :class="{ active: marketTab === 'armor' }" @click="marketTab = 'armor'">防具</button>
                <button class="market-tab" :class="{ active: marketTab === 'materials' }" @click="marketTab = 'materials'">材料</button>
              </div>
              
              <div class="shop-items">
                <div v-for="(item, index) in getMarketItems()" :key="index" class="shop-item">
                  <div class="item-icon">{{ item.icon }}</div>
                  <div class="item-info">
                    <div class="item-name">{{ item.name }}</div>
                    <div class="item-desc">{{ item.description }}</div>
                    <div class="item-stats" v-if="item.attack || item.defense || item.effect">
                      {{ getItemStatsText(item) }}
                    </div>
                  </div>
                  <div class="item-actions">
                    <div class="item-price">{{ item.price }} 两</div>
                    <button 
                      @click="buyItem(item)" 
                      class="buy-btn"
                      :disabled="player.money < item.price"
                    >
                      购买
                    </button>
                  </div>
                </div>
              </div>
            </div>
            
            <!-- 悬赏榜界面 -->
            <div class="quest-area" v-if="currentDistrict === 'quest'">
              <h3>📜 悬赏榜 - 赏金任务</h3>
              <div class="quest-board">
                <div class="active-quest" v-if="player.activeQuest">
                  <div class="quest-header">
                    <div class="quest-title">当前任务: {{ player.activeQuest.name }}</div>
                    <button @click="abandonQuest" class="abandon-btn">放弃任务</button>
                  </div>
                  <div class="quest-content">
                    <div class="quest-desc">{{ player.activeQuest.description }}</div>
                    <div class="quest-progress">
                      <div class="progress-bar">
                        <div class="progress-fill" :style="{width: (player.questProgress / player.activeQuest.target) * 100 + '%'}"></div>
                      </div>
                      <div class="progress-text">进度: {{ player.questProgress }}/{{ player.activeQuest.target }}</div>
                    </div>
                    <div class="quest-rewards">
                      <span class="reward">赏金: {{ player.activeQuest.reward }}两</span>
                      <span class="reward">修为: {{ player.activeQuest.xpReward }}</span>
                      <span class="reward" v-if="player.activeQuest.itemReward">奖励: {{ player.activeQuest.itemReward }}</span>
                    </div>
                  </div>
                </div>
                
                <div class="available-quests">
                  <h4>可接任务</h4>
                  <div class="quest-list">
                    <div v-for="(quest, index) in availableQuests" :key="index" class="quest-card">
                      <div class="quest-card-content">
                        <div class="quest-card-title">{{ quest.name }}</div>
                        <div class="quest-card-desc">{{ quest.description }}</div>
                        <div class="quest-card-rewards">
                          <div class="quest-reward">赏金: {{ quest.reward }}两</div>
                          <div class="quest-reward">修为: {{ quest.xpReward }}</div>
                        </div>
                      </div>
                      <button @click="acceptQuest(quest)" class="accept-btn" :disabled="player.activeQuest">接受</button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <!-- 背包界面 -->
          <div class="inventory-area" v-if="gameState === 'inventory'">
            <div class="inventory-header">
              <h2>🎒 背包</h2>
              <div class="inventory-stats">
                <span>负重: {{ inventoryWeight }}/{{ maxInventoryWeight }}</span>
                <span>物品: {{ totalItems }} 件</span>
              </div>
            </div>
            
            <div class="inventory-tabs">
              <button class="inv-tab" :class="{ active: inventoryTab === 'all' }" @click="inventoryTab = 'all'">全部</button>
              <button class="inv-tab" :class="{ active: inventoryTab === 'potions' }" @click="inventoryTab = 'potions'">药品</button>
              <button class="inv-tab" :class="{ active: inventoryTab === 'weapons' }" @click="inventoryTab = 'weapons'">武器</button>
              <button class="inv-tab" :class="{ active: inventoryTab === 'armor' }" @click="inventoryTab = 'armor'">防具</button>
              <button class="inv-tab" :class="{ active: inventoryTab === 'materials' }" @click="inventoryTab = 'materials'">材料</button>
            </div>
            
            <div class="inventory-grid">
              <div v-for="(item, index) in getFilteredInventory()" :key="index" class="inventory-item">
                <div class="item-display">
                  <div class="item-icon">{{ item.icon }}</div>
                  <div class="item-quantity" v-if="item.quantity > 1">x{{ item.quantity }}</div>
                </div>
                <div class="item-details">
                  <div class="item-name">{{ item.name }}</div>
                  <div class="item-type">{{ getItemTypeText(item.type) }}</div>
                </div>
                <div class="item-actions">
                  <button @click="useInventoryItem(item)" v-if="item.type === 'potion'" class="inv-action use">使用</button>
                  <button @click="equipItem(item)" v-if="item.type === 'weapon' || item.type === 'armor' || item.type === 'accessory'" class="inv-action equip">装备</button>
                  <button @click="sellItem(item)" class="inv-action sell">出售</button>
                </div>
              </div>
            </div>
          </div>
        </div>

        <!-- 游戏日志 -->
        <div class="game-log">
          <div class="log-header">
