  computed: {
    playerHpPercent() {
      return Math.max(0, (this.player.hp / this.player.maxHp) * 100);
    },
    playerMpPercent() {
      return Math.max(0, (this.player.mp / this.player.maxMp) * 100);
    },
    enemyHpPercent() {
      if (!this.currentEnemy) return 0;
      return Math.max(0, (this.currentEnemy.hp / this.currentEnemy.maxHp) * 100);
    },
    xpToNextLevel() {
      return this.player.level * 100;
    },
    xpPercent() {
      return Math.min(100, (this.player.xp / this.xpToNextLevel) * 100);
    },
    fleeChance() {
      return Math.min(80, this.player.agility * 2 + 20);
    },
    treasureChance() {
      return 40 + this.player.agility;
    },
    availableQuests() {
      return this.quests.filter(quest => {
        // 显示未接取的任务
        if (this.player.activeQuest && this.player.activeQuest.name === quest.name) {
          return false;
        }
        // 根据玩家等级筛选合适难度的任务
        if (quest.enemyType === '邪派长老' && this.player.level < 5) return false;
        if (quest.enemyType === '采花大盗' && this.player.level < 3) return false;
        return true;
      });
    },
    inventoryWeight() {
      return this.player.inventory.reduce((total, item) => {
        return total + (item.weight || 1) * item.quantity;
      }, 0);
    },
    maxInventoryWeight() {
      return 50 + this.player.level * 10;
    },
    totalItems() {
      return this.player.inventory.reduce((total, item) => total + item.quantity, 0);
    }
  },
  methods: {
    // 游戏状态切换
    switchState(state) {
      this.gameState = state;
      if (state === 'town') {
        this.currentDistrict = 'market';
      }
    },
    
    // 选择技能
    selectSkill(index) {
      if (this.player.skills[index].locked) return;
      this.currentSkill = index;
      this.addEventLog(`选择招式：${this.player.skills[index].name}`, 'skill');
    },
    
    // 使用技能
    useSkill(skillIndex) {
      if (!this.isPlayerTurn || this.player.mp < this.player.skills[skillIndex].cost) return;
      
      const skill = this.player.skills[skillIndex];
      this.player.mp -= skill.cost;
      
      let damage = 0;
      let logText = '';
      
      // 计算伤害或治疗效果
      if (skill.type === 'heal') {
        const healAmount = skill.healAmount * (1 + (skill.level - 1) * 0.2);
        this.player.hp = Math.min(this.player.maxHp, this.player.hp + healAmount);
        logText = `你施展${skill.name}，恢复${Math.round(healAmount)}点生命值`;
        this.addBattleLog(logText, 'player');
      } else {
        // 基础伤害计算
        const baseDamage = this.player.attack * skill.damageMultiplier;
        
        // 装备加成
        const equipmentBonus = this.getEquipmentAttack();
        
        // 暴击计算
        let isCritical = false;
        let critMultiplier = 1;
        if (Math.random() * 100 < this.player.critRate) {
          isCritical = true;
          critMultiplier = 1.5;
        }
        
        // 最终伤害计算
        damage = Math.max(1, Math.floor((baseDamage + equipmentBonus) * critMultiplier - this.currentEnemy.defense * 0.5));
        
        // 技能特效
        let effectText = '';
        if (skill.effect === 'doubleAttack' && Math.random() > 0.6) {
          damage *= 2;
          effectText = '，触发连击效果';
        } else if (skill.effect === 'armorBreak' && Math.random() > 0.7) {
          this.currentEnemy.defense = Math.max(1, this.currentEnemy.defense - 2);
          effectText = '，破除了对方的防御';
        } else if (skill.effect === 'dodge' && Math.random() > 0.5) {
          this.player.status = { name: '闪避提升', type: 'buff', turns: 2 };
          effectText = '，身法变得飘忽不定';
        }
        
        // 暴击文本
        const critText = isCritical ? '（暴击！）' : '';
        
        this.currentEnemy.hp -= damage;
        logText = `你施展${skill.name}${critText}，对${this.currentEnemy.name}造成${damage}点伤害${effectText}`;
        this.addBattleLog(logText, 'player');
        
        // 技能经验
        this.gainSkillExp(skillIndex);
      }
      
      // 检查敌人是否被击败
      if (this.currentEnemy.hp <= 0) {
        this.endBattle(true);
        return;
      }
      
      // 切换到敌人回合
      this.isPlayerTurn = false;
      setTimeout(() => this.enemyTurn(), 1000);
    },
    
    // 技能经验获取
    gainSkillExp(skillIndex) {
      const skill = this.player.skills[skillIndex];
      if (skill.level < skill.maxLevel) {
        // 这里可以添加技能经验系统
      }
    },
    
    // 计算技能伤害
    calculateSkillDamage(skill) {
      if (skill.type === 'heal') return `治疗${skill.healAmount}`;
      
      const baseDamage = this.player.attack * skill.damageMultiplier;
      const equipmentBonus = this.getEquipmentAttack();
      const minDamage = Math.max(1, Math.floor((baseDamage + equipmentBonus) * 0.8));
      const maxDamage = Math.max(1, Math.floor((baseDamage + equipmentBonus) * 1.2));
      
      return `${minDamage}-${maxDamage}`;
    },
    
    // 敌人回合
    enemyTurn() {
      if (this.currentEnemy.hp <= 0) return;
      
      // 检查玩家是否有闪避状态
      let dodgeChance = 0;
      if (this.player.status && this.player.status.name === '闪避提升') {
        dodgeChance = 0.3;
        this.player.status.turns--;
        if (this.player.status.turns <= 0) {
          this.player.status = null;
        }
      }
      
      if (Math.random() < dodgeChance) {
        const logText = `${this.currentEnemy.name}的攻击被你灵活躲开`;
        this.addBattleLog(logText, 'dodge');
      } else {
        // 简单AI：随机选择攻击方式
        const damage = Math.max(1, this.currentEnemy.attack - Math.floor(this.player.defense * 0.7));
        this.player.hp -= damage;
        
        const logText = `${this.currentEnemy.name}对你造成${damage}点伤害`;
        this.addBattleLog(logText, 'enemy');
      }
      
      // 检查玩家是否被击败
      if (this.player.hp <= 0) {
        this.endBattle(false);
        return;
      }
      
      // 切换回玩家回合
      this.isPlayerTurn = true;
    },
    
    // 防御
    defend() {
      if (!this.isPlayerTurn) return;
      
      this.player.status = { name: '防御姿态', type: 'buff', turns: 1, defenseBonus: 5 };
      this.addBattleLog('你采取防御姿态，下回合防御力提升', 'player');
      
      this.isPlayerTurn = false;
      setTimeout(() => this.enemyTurn(), 1000);
    },
    
    // 结束战斗
    endBattle(playerWon) {
      if (playerWon) {
        const xpReward = this.currentEnemy.xpReward;
        const moneyReward = this.currentEnemy.moneyReward;
        
        this.player.xp += xpReward;
        this.player.money += moneyReward;
        
        this.addBattleLog(`你击败了${this.currentEnemy.name}，获得${xpReward}修为和${moneyReward}两银子`, 'victory');
        
        // 掉落物品
        this.checkEnemyLoot();
        
        // 检查任务进度
        if (this.player.activeQuest && this.player.activeQuest.enemyType === this.currentEnemy.name) {
          this.player.questProgress++;
          this.addEventLog(`任务进度更新：${this.player.activeQuest.name} (${this.player.questProgress}/${this.player.activeQuest.target})`, 'quest');
          
          if (this.player.questProgress >= this.player.activeQuest.target) {
            this.completeQuest();
          }
        }
        
        // 检查是否升级
        if (this.player.xp >= this.xpToNextLevel) {
          this.levelUp();
        }
        
        // 检查成就
        this.checkAchievements();
      } else {
        this.addBattleLog(`你被${this.currentEnemy.name}击败，江湖路远，请多加小心`, 'defeat');
        this.player.hp = Math.floor(this.player.maxHp * 0.3); // 恢复部分生命
        this.player.mp = Math.floor(this.player.maxMp * 0.3); // 恢复部分内力
      }
      
      // 延迟返回世界地图
      setTimeout(() => {
        this.gameState = 'world';
        this.battleLog = [];
        this.currentEnemy = null;
        this.isPlayerTurn = true;
        this.player.status = null;
      }, 3000);
    },
    
    // 检查敌人掉落
    checkEnemyLoot() {
      if (this.currentEnemy.loot) {
        this.currentEnemy.loot.forEach(loot => {
          if (Math.random() < loot.chance) {
            // 这里可以添加具体的掉落物品逻辑
            this.addEventLog(`从${this.currentEnemy.name}身上获得了物品`, 'loot');
          }
        });
      }
    },
    
    // 检查成就
    checkAchievements() {
      // 首杀成就
      if (!this.achievements.find(a => a.id === 'first_kill').unlocked) {
        this.achievements.find(a => a.id === 'first_kill').unlocked = true;
        this.addEventLog('达成成就：首战告捷', 'achievement');
      }
      
      // 等级成就
      if (this.player.level >= 5 && !this.achievements.find(a => a.id === 'level_5').unlocked) {
        this.achievements.find(a => a.id === 'level_5').unlocked = true;
        this.addEventLog('达成成就：初露锋芒', 'achievement');
      }
      
      // 财富成就
      if (this.player.money >= 1000 && !this.achievements.find(a => a.id === 'rich_man').unlocked) {
        this.achievements.find(a => a.id === 'rich_man').unlocked = true;
        this.addEventLog('达成成就：富甲一方', 'achievement');
      }
    },
    
    // 逃离战斗
    fleeBattle() {
      if (Math.random() * 100 < this.fleeChance) {
        this.addBattleLog(`你施展轻功，成功逃离战斗`, 'flee');
        setTimeout(() => {
          this.gameState = 'world';
          this.battleLog = [];
          this.currentEnemy = null;
          this.isPlayerTurn = true;
        }, 1500);
      } else {
        this.addBattleLog(`逃离失败，${this.currentEnemy.name}追上了你`, 'flee-fail');
        this.isPlayerTurn = false;
        setTimeout(() => this.enemyTurn(), 1000);
      }
    },
    
    // 探索江湖
    explore() {
      if (this.isExploring) return;
      
      this.isExploring = true;
      this.exploreTimer = 5;
      
      this.addEventLog(`开始在${this.currentLocation.name}探索...`, 'explore');
      
      const exploreInterval = setInterval(() => {
        this.exploreTimer--;
        
        if (this.exploreTimer <= 0) {
          clearInterval(exploreInterval);
          this.isExploring = false;
          this.exploreTimer = 0;
          
          const randomEvent = Math.random();
          
          if (randomEvent < 0.5) {
            // 遇到敌人
            const enemyIndex = Math.floor(Math.random() * Math.min(this.player.level + 1, this.enemies.length));
            this.currentEnemy = { ...this.enemies[enemyIndex] };
            this.currentEnemy.hp = this.currentEnemy.maxHp;
            
            // 根据玩家等级调整敌人强度
            if (this.player.level > 1) {
              const levelMultiplier = 1 + (this.player.level - 1) * 0.2;
              this.currentEnemy.maxHp = Math.floor(this.currentEnemy.maxHp * levelMultiplier);
              this.currentEnemy.hp = this.currentEnemy.maxHp;
              this.currentEnemy.attack = Math.floor(this.currentEnemy.attack * levelMultiplier);
              this.currentEnemy.xpReward = Math.floor(this.currentEnemy.xpReward * levelMultiplier);
              this.currentEnemy.moneyReward = Math.floor(this.currentEnemy.moneyReward * levelMultiplier);
            }
            
            this.gameState = 'battle';
            this.addEventLog(`你在${this.currentLocation.name}遭遇了${this.currentEnemy.name}`, 'encounter');
          } else if (randomEvent < 0.8) {
            // 发现宝物
            const moneyFound = Math.floor(Math.random() * 50) + 10 * this.player.level;
            this.player.money += moneyFound;
            this.addEventLog(`你在${this.currentLocation.name}发现了一些银两，获得${moneyFound}两`, 'treasure');
            
            // 随机更换地点
            this.changeLocation();
          } else if (randomEvent < 0.95) {
            // 发现材料
            const materials = ['草药', '矿石', '兽皮', '珍稀木材'];
            const material = materials[Math.floor(Math.random() * materials.length)];
            this.addEventLog(`你在${this.currentLocation.name}发现了一些${material}`, 'material');
            this.changeLocation();
          } else {
            // 特殊事件
            this.addEventLog(`你在${this.currentLocation.name}探索时，发现了一处隐藏的洞穴`, 'special');
            this.changeLocation();
          }
        }
      }, 1000);
    },
    
    // 打坐调息
    meditate() {
      const hpRecover = Math.floor(this.player.maxHp * 0.3);
      const mpRecover = Math.floor(this.player.maxMp * 0.5);
      
      this.player.hp = Math.min(this.player.maxHp, this.player.hp + hpRecover);
      this.player.mp = Math.min(this.player.maxMp, this.player.mp + mpRecover);
      
      this.addEventLog(`你打坐调息，恢复了${hpRecover}点生命和${mpRecover}点内力`, 'meditate');
      
      // 增加游戏时间
      this.gameTime += 0.5;
    },
    
    // 快速打坐
    quickMeditate() {
      if (this.player.hp >= this.player.maxHp && this.player.mp >= this.player.maxMp) return;
      this.meditate();
    },
    
    // 前往城镇
    visitTown() {
      this.gameState = 'town';
      this.addEventLog('你来到了襄阳城', 'town');
      
      // 增加游戏时间
      this.gameTime += 1;
    },
    
    // 访问城镇区域
    visitDistrict(district) {
      this.currentDistrict = district;
      switch(district) {
        case 'market':
          this.addEventLog('来到了集市，这里可以购买各种物品', 'town');
          break;
        case 'quest':
          this.addEventLog('来到了悬赏榜，这里有许多赏金任务', 'town');
          break;
        case 'inn':
          this.addEventLog('来到了客栈，可以休息恢复状态', 'town');
          // 在客栈可以恢复全部状态
          this.player.hp = this.player.maxHp;
          this.player.mp = this.player.maxMp;
          this.addEventLog('在客栈休息后，状态完全恢复', 'heal');
          break;
        case 'arena':
          this.addEventLog('来到了比武场，这里有许多武林高手', 'town');
          break;
      }
    },
    
    // 修炼武功
    train() {
      if (this.isTraining) return;
      
      this.isTraining = true;
      this.trainTimer = 10;
      
      this.addEventLog(`开始修炼武功...`, 'train');
      
      const trainInterval = setInterval(() => {
        this.trainTimer--;
        
        if (this.trainTimer <= 0) {
          clearInterval(trainInterval);
          this.isTraining = false;
          this.trainTimer = 0;
          
          const xpGain = Math.floor(Math.random() * 20) + 10 + this.player.level * 5;
          this.player.xp += xpGain;
          
          // 小概率获得新技能
          if (Math.random() > 0.9 && this.player.skills.length < 6) {
            const lockedSkills = this.player.skills.filter(skill => skill.locked);
            if (lockedSkills.length > 0) {
              const skillToUnlock = lockedSkills[0];
              skillToUnlock.locked = false;
              skillToUnlock.level = 1;
              this.addEventLog(`你修炼时领悟了新招式：${skillToUnlock.name}`, 'skill-learned');
            }
          } else {
            this.addEventLog(`你潜心修炼，获得${xpGain}点修为`, 'train');
          }
          
          // 检查是否升级
          if (this.player.xp >= this.xpToNextLevel) {
            this.levelUp();
          }
          
          // 增加游戏时间
          this.gameTime += 1;
        }
      }, 1000);
    },
    
    // 寻宝探秘
    huntTreasure() {
      if (this.isHunting) return;
      
      this.isHunting = true;
      this.addEventLog('开始寻宝探秘...', 'explore');
      
      setTimeout(() => {
        this.isHunting = false;
        
        if (Math.random() * 100 < this.treasureChance) {
          // 寻宝成功
          const treasureValue = Math.floor(Math.random() * 100) + 50;
          this.player.money += treasureValue;
          
          // 可能获得装备
          if (Math.random() > 0.7) {
            const possibleItems = ['精铁剑', '皮甲', '翡翠玉佩'];
            const item = possibleItems[Math.floor(Math.random() * possibleItems.length)];
            this.addEventLog(`你发现了一处宝藏，获得${treasureValue}两银子和${item}`, 'treasure');
          } else {
            this.addEventLog(`你发现了一处宝藏，获得${treasureValue}两银子`, 'treasure');
          }
        } else {
          // 寻宝失败，可能遇到敌人
          if (Math.random() > 0.5) {
            this.addEventLog('寻宝过程中没有发现什么有价值的东西', 'explore');
          } else {
            const enemyIndex = Math.floor(Math.random() * 2); // 遇到较弱敌人
            this.currentEnemy = { ...this.enemies[enemyIndex] };
            this.currentEnemy.hp = this.currentEnemy.maxHp;
            this.gameState = 'battle';
            this.addEventLog(`寻宝时惊动了附近的${this.currentEnemy.name}`, 'encounter');
          }
        }
        
        // 增加游戏时间
        this.gameTime += 0.5;
      }, 2000);
    },
    
    // 擂台比武
    challengeArena() {
      if (this.currentLocation.type !== '擂台') return;
      
      // 创建擂台对手
      const arenaEnemies = [
        { name: '武馆学徒', maxHp: 80, hp: 80, attack: 15, defense: 10, agility: 12, xpReward: 100, moneyReward: 100 },
        { name: '江湖镖师', maxHp: 120, hp: 120, attack: 20, defense: 15, agility: 10, xpReward: 150, moneyReward: 150 },
        { name: '武林名宿', maxHp: 200, hp: 200, attack: 30, defense: 20, agility: 8, xpReward: 300, moneyReward: 300 }
      ];
      
      const enemyIndex = Math.min(this.player.level - 1, arenaEnemies.length - 1);
      this.currentEnemy = { ...arenaEnemies[enemyIndex] };
      this.currentEnemy.hp = this.currentEnemy.maxHp;
      
      this.gameState = 'battle';
      this.addEventLog(`你登上擂台，挑战${this.currentEnemy.name}`, 'arena');
    },
    
    // 购买物品
    buyItem(item) {
      if (this.player.money < item.price) {
        this.addEventLog('银两不足，无法购买', 'error');
        return;
      }
      
      this.player.money -= item.price;
      
      // 添加到背包
      const existingItem = this.player.inventory.find(i => i.id === item.id);
      if (existingItem) {
        existingItem.quantity++;
      } else {
        this.player.inventory.push({
          id: item.id,
          name: item.name,
          type: item.type,
          quantity: 1,
          icon: item.icon,
          ...item.effect && { effect: item.effect },
          ...item.attack && { attack: item.attack },
          ...item.defense && { defense: item.defense }
        });
      }
      
      this.addEventLog(`购买了${item.name}，花费${item.price}两`, 'buy');
      
      // 检查成就
      if (item.type === 'weapon' || item.type === 'armor' || item.type === 'accessory') {
        const hasAllTypes = ['weapon', 'armor', 'accessory'].every(type => 
          this.player.inventory.some(item => item.type === type)
        );
        
        if (hasAllTypes && !this.achievements.find(a => a.id === 'shopaholic').unlocked) {
          this.achievements.find(a => a.id === 'shopaholic').unlocked = true;
          this.addEventLog('达成成就：购物狂', 'achievement');
        }
      }
    },
    
    // 获取市场物品
    getMarketItems() {
      return this.shopItems[this.marketTab] || [];
    },
    
    // 接受任务
    acceptQuest(quest) {
      if (this.player.activeQuest) {
        this.addEventLog('你已有悬赏在身，先完成当前任务吧', 'quest');
        return;
      }
      
      this.player.activeQuest = { ...quest };
      this.player.questProgress = 0;
      
      this.addEventLog(`你接受了悬赏：${this.player.activeQuest.name}`, 'quest-accept');
      
      // 切换到任务追踪
      this.currentDistrict = 'quest';
    },
    
    // 放弃任务
    abandonQuest() {
      if (!this.player.activeQuest) return;
      
      const questName = this.player.activeQuest.name;
      this.player.activeQuest = null;
      this.player.questProgress = 0;
      
      this.addEventLog(`放弃了任务：${questName}`, 'quest');
    },
    
    // 完成任务
    completeQuest() {
      const reward = this.player.activeQuest.reward;
      const xpReward = this.player.activeQuest.xpReward;
      
      this.player.money += reward;
      this.player.xp += xpReward;
      
      this.addEventLog(`你完成了悬赏${this.player.activeQuest.name}，获得${reward}两银子和${xpReward}点修为`, 'quest-complete');
      
      // 检查成就
      const questAchievement = this.achievements.find(a => a.id === 'quest_complete');
      if (questAchievement && !questAchievement.unlocked) {
        // 这里可以添加任务计数逻辑
      }
      
      this.player.activeQuest = null;
      this.player.questProgress = 0;
      
      // 检查是否升级
      if (this.player.xp >= this.xpToNextLevel) {
        this.levelUp();
      }
    },
    
    // 离开城镇
    leaveTown() {
      this.gameState = 'world';
      this.addEventLog('你离开襄阳城，重返江湖', 'town');
    },
    
    // 更换地点
    changeLocation() {
      const newLocationIndex = Math.floor(Math.random() * this.locations.length);
      this.currentLocation = this.locations[newLocationIndex];
      this.addEventLog(`来到了${this.currentLocation.name}`, 'location');
      
      // 增加游戏时间
      this.gameTime += 0.5;
    },
    
    // 升级
    levelUp() {
      this.player.level++;
      this.player.maxHp += 20;
      this.player.maxMp += 15;
      this.player.attack += 3;
      this.player.defense += 2;
      this.player.agility += 1;
      this.player.critRate += 0.5;
      
      // 恢复所有生命和内力
      this.player.hp = this.player.maxHp;
      this.player.mp = this.player.maxMp;
      
      // 根据等级更新称号
      if (this.player.level >= 10) {
        this.player.className = '武林宗师';
        this.player.class = 'grandmaster';
      } else if (this.player.level >= 5) {
        this.player.className = '武林高手';
        this.player.class = 'master';
      } else if (this.player.level >= 3) {
        this.player.className = '江湖侠客';
        this.player.class = 'swordsman';
      }
      
      this.showLevelUp = true;
      this.addEventLog(`恭喜！你的武学修为突破到新的境界，达到${this.player.level}级`, 'level-up');
      
      // 自动保存
      if (this.settings.autoSave) {
        this.quickSave();
      }
    },
    
    // 装备系统
    showEquipmentModal(type) {
      this.showEquipmentModalType = type;
    },
    
    closeEquipmentModal() {
      this.showEquipmentModalType = null;
    },
    
    getEquipmentByType(type) {
      switch(type) {
        case 'weapon':
          return this.shopItems.weapons;
        case 'armor':
          return this.shopItems.armor;
        case 'accessory':
          return this.shopItems.accessories;
        default:
          return [];
      }
    },
    
    isEquipped(item) {
      const equipment = this.player.equipment[this.showEquipmentModalType];
      return equipment && equipment.id === item.id;
    },
    
    equipItem(item) {
      const slot = this.showEquipmentModalType;
      
      // 如果已经装备了物品，先卸下
      if (this.player.equipment[slot]) {
        const oldItem = this.player.equipment[slot];
        this.addToInventory(oldItem);
      }
      
      // 装备新物品
      this.player.equipment[slot] = { ...item };
      
      // 从背包中移除
      const invIndex = this.player.inventory.findIndex(i => i.id === item.id);
      if (invIndex !== -1) {
        this.player.inventory[invIndex].quantity--;
        if (this.player.inventory[invIndex].quantity <= 0) {
          this.player.inventory.splice(invIndex, 1);
        }
      }
      
      this.addEventLog(`装备了${item.name}`, 'equip');
      this.closeEquipmentModal();
    },
    
    addToInventory(item) {
      const existingItem = this.player.inventory.find(i => i.id === item.id);
      if (existingItem) {
        existingItem.quantity++;
      } else {
        this.player.inventory.push({
          id: item.id,
          name: item.name,
          type: item.type,
          quantity: 1,
          icon: item.icon,
          ...item.effect && { effect: item.effect },
          ...item.attack && { attack: item.attack },
          ...item.defense && { defense: item.defense }
        });
      }
    },
    
    getEquipmentAttack() {
      let attack = 0;
      if (this.player.equipment.weapon) {
        attack += this.player.equipment.weapon.attack || 0;
      }
      if (this.player.equipment.accessory && this.player.equipment.accessory.effect) {
        attack += this.player.equipment.accessory.effect.attack || 0;
      }
      return attack;
    },
    
    getEquipmentDefense() {
      let defense = 0;
      if (this.player.equipment.armor) {
        defense += this.player.equipment.armor.defense || 0;
      }
      if (this.player.equipment.accessory && this.player.equipment.accessory.effect) {
        defense += this.player.equipment.accessory.effect.defense || 0;
      }
      return defense;
    },
    
    getAccessoryEffectText() {
      if (!this.player.equipment.accessory || !this.player.equipment.accessory.effect) return '';
      
      const effect = this.player.equipment.accessory.effect;
      if (effect.mpRegen) return `内力恢复+${effect.mpRegen}`;
      if (effect.attack) return `攻击+${effect.attack}`;
      if (effect.maxHp) return `生命+${effect.maxHp}`;
      if (effect.defense) return `防御+${effect.defense}`;
      return '特殊效果';
    },
    
    // 背包系统
    getFilteredInventory() {
      if (this.inventoryTab === 'all') return this.player.inventory;
      return this.player.inventory.filter(item => item.type === this.inventoryTab);
    },
    
    getItemTypeText(type) {
      const typeMap = {
        potion: '药品',
        weapon: '武器',
        armor: '防具',
        accessory: '饰品',
        material: '材料'
      };
      return typeMap[type] || '未知';
    },
    
    getItemCount(type) {
      const item = this.player.inventory.find(i => i.id === `potion_${type}`);
      return item ? item.quantity : 0;
    },
    
    useInventoryItem(item) {
      if (item.type !== 'potion') return;
      
      if (item.effect.hp) {
        this.player.hp = Math.min(this.player.maxHp, this.player.hp + item.effect.hp);
        this.addEventLog(`使用了${item.name}，恢复${item.effect.hp}点生命`, 'heal');
      } else if (item.effect.mp) {
        this.player.mp = Math.min(this.player.maxMp, this.player.mp + item.effect.mp);
        this.addEventLog(`使用了${item.name}，恢复${item.effect.mp}点内力`, 'mana');
      } else if (item.effect.hp === 'full') {
        this.player.hp = this.player.maxHp;
        this.player.mp = this.player.maxMp;
        this.addEventLog(`使用了${item.name}，状态完全恢复`, 'heal');
      }
      
      // 减少数量
      item.quantity--;
      if (item.quantity <= 0) {
        const index = this.player.inventory.indexOf(item);
        this.player.inventory.splice(index, 1);
      }
    },
    
    // 快速使用药品
    quickHeal() {
      const healingPotion = this.player.inventory.find(item => item.id === 'potion_healing');
      if (healingPotion) {
        this.useInventoryItem(healingPotion);
      }
    },
    
    useItem(type) {
      const itemId = `potion_${type}`;
      const item = this.player.inventory.find(i => i.id === itemId);
      if (item) {
        this.useInventoryItem(item);
      }
    },
    
    sellItem(item) {
      // 计算物品价格（购买价的70%）
      const shopItem = Object.values(this.shopItems)
        .flat()
        .find(shopItem => shopItem.id === item.id);
      
      if (!shopItem) return;
      
      const sellPrice = Math.floor(shopItem.price * 0.7);
      this.player.money += sellPrice;
      
      // 从背包移除
      item.quantity--;
      if (item.quantity <= 0) {
        const index = this.player.inventory.indexOf(item);
        this.player.inventory.splice(index, 1);
      }
      
      this.addEventLog(`出售了${item.name}，获得${sellPrice}两`, 'sell');
    },
    
    getItemStatsText(item) {
      if (item.attack) return `攻击+${item.attack}`;
      if (item.defense) return `防御+${item.defense}`;
      if (item.effect) {
        if (item.effect.hp) return `恢复生命${item.effect.hp}`;
        if (item.effect.mp) return `恢复内力${item.effect.mp}`;
      }
      return '';
    },
    
    // 日志系统
    addBattleLog(text, type) {
      this.battleLog.unshift({ 
        text, 
        type,
        time: new Date()
      });
      if (this.battleLog.length > 10) {
        this.battleLog.pop();
      }
    },
    
    addEventLog(text, type) {
      this.eventLog.unshift({ 
        text, 
        type,
        time: new Date()
      });
      if (this.eventLog.length > 20) {
        this.eventLog.pop();
      }
      
      // 同时添加到系统消息
      this.systemMessages.unshift({
        text,
        time: new Date()
      });
      if (this.systemMessages.length > 5) {
        this.systemMessages.pop();
      }
    },
    
    clearLog() {
      this.eventLog = [];
      this.addEventLog('日志已清空', 'system');
    },
    
    formatTime(date) {
      if (!date) return '';
      const time = new Date(date);
      return `${time.getHours().toString().padStart(2, '0')}:${time.getMinutes().toString().padStart(2, '0')}`;
    },
    
    // 获取游戏状态文本
    getGameStateText() {
      switch(this.gameState) {
        case 'world': return '闯荡江湖中';
        case 'battle': return '战斗中';
        case 'town': return '襄阳城内';
        case 'inventory': return '查看背包';
        default: return '未知状态';
      }
    },
    
    // 游戏设置
    saveSettings() {
      localStorage.setItem('wuxiaGameSettings', JSON.stringify(this.settings));
      this.addEventLog('游戏设置已保存', 'save');
      this.showSettings = false;
    },
    
    loadSettings() {
      const savedSettings = localStorage.getItem('wuxiaGameSettings');
      if (savedSettings) {
        this.settings = JSON.parse(savedSettings);
      }
    },
    
    // 保存游戏
    saveGame() {
      const saveData = {
        player: this.player,
        gameState: this.gameState,
        currentLocation: this.currentLocation,
        eventLog: this.eventLog,
        gameTime: this.gameTime,
        achievements: this.achievements
      };
      
      localStorage.setItem('wuxiaGameSave', JSON.stringify(saveData));
      this.addEventLog('游戏进度已保存', 'save');
    },
    
    // 快速保存
    quickSave() {
      this.saveGame();
      this.addEventLog('已自动保存进度', 'save');
    },
    
    // 读取游戏
    loadGame() {
      const saveData = localStorage.getItem('wuxiaGameSave');
      if (saveData) {
        const loadedData = JSON.parse(saveData);
        this.player = loadedData.player;
        this.gameState = loadedData.gameState;
        this.currentLocation = loadedData.currentLocation;
        this.eventLog = loadedData.eventLog;
        this.gameTime = loadedData.gameTime;
        this.achievements = loadedData.achievements || this.achievements;
        this.addEventLog('游戏进度已读取', 'load');
      } else {
        this.addEventLog('没有找到保存的游戏进度', 'load');
      }
    },
    
    // 重置游戏
    resetGame() {
      if (confirm('确定要重新开始游戏吗？当前进度将丢失。')) {
        // 重置玩家数据
        this.player = {
          name: '游侠',
          className: '江湖游侠',
          class: 'wanderer',
          level: 1,
          xp: 0,
          maxHp: 100,
          hp: 100,
          maxMp: 50,
          mp: 50,
          attack: 15,
          defense: 10,
          agility: 12,
          critRate: 5,
          money: 100,
          skills: [
            { 
              name: '基础剑法', 
              description: '普通攻击，消耗内力少', 
              cost: 5, 
              damageMultiplier: 1.0, 
              type: 'physical',
              level: 1,
              maxLevel: 10
            },
            { 
              name: '狂风快剑', 
              description: '快速攻击，可能连击', 
              cost: 15, 
              damageMultiplier: 1.5, 
              type: 'physical', 
              effect: 'doubleAttack',
              level: 1,
              maxLevel: 5
            },
            { 
              name: '金刚掌', 
              description: '重击，可能破防', 
              cost: 20, 
              damageMultiplier: 2.0, 
              type: 'physical', 
              effect: 'armorBreak',
              level: 1,
              maxLevel: 5
            },
            { 
              name: '内劲疗伤', 
              description: '消耗内力恢复生命', 
              cost: 25, 
              damageMultiplier: 0, 
              type: 'heal', 
              healAmount: 30,
              level: 1,
              maxLevel: 3
            },
            { 
              name: '飞燕剑法', 
              description: '灵巧剑法，提高闪避几率', 
              cost: 18, 
              damageMultiplier: 1.3, 
              type: 'physical', 
              effect: 'dodge',
              level: 0,
              maxLevel: 3,
              locked: true
            }
          ],
          status: null,
          activeQuest: null,
          questProgress: 0,
          equipment: {
            weapon: null,
            armor: null,
            accessory: null
          },
          inventory: [
            { id: 'potion_healing', name: '金疮药', type: 'potion', quantity: 3, icon: '❤️', effect: { hp: 50 } },
            { id: 'potion_mana', name: '回气散', type: 'potion', quantity: 2, icon: '💠', effect: { mp: 30 } }
          ]
        };
        
        this.gameState = 'world';
        this.currentLocation = {
          name: '华山脚下',
          type: '名山',
          description: '华山巍峨耸立，山脚下有不少武林人士在此切磋武艺。',
          features: [
            { icon: '⚔️', text: '适合练剑' },
            { icon: '🧘', text: '灵气充沛' },
            { icon: '👥', text: '人烟稀少' }
          ]
        };
        this.currentEnemy = null;
        this.battleLog = [];
        this.eventLog = [];
        this.systemMessages = [];
        this.isPlayerTurn = true;
        this.showLevelUp = false;
        this.gameTime = 1;
        
        // 重置成就
        this.achievements.forEach(achievement => {
          if (achievement.id !== 'first_kill') {
            achievement.unlocked = false;
          }
        });
        
        this.addEventLog('新的武侠传奇开始，少侠请重新启程', 'reset');
      }
    }
  },
  mounted() {
    // 初始化事件日志
    this.addEventLog('江湖风云起，仗剑走天涯。少侠，你的武侠传奇开始了！', 'start');
    this.addEventLog('你来到华山脚下，准备开始闯荡江湖', 'location');
    
    // 加载设置
    this.loadSettings();
    
    // 自动保存检查
    if (this.settings.autoSave) {
      setInterval(() => {
        if (this.gameTime % 5 === 0) { // 每5天自动保存一次
          this.quickSave();
        }
      }, 60000); // 每分钟检查一次
    }
  }
}
</script>

<style>
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Microsoft YaHei', 'SimHei', 'STKaiti', sans-serif;
  background: linear-gradient(135deg, #0c1a1f 0%, #1a3a3a 100%);
  color: #e6d3a7;
  min-height: 100vh;
  padding: 20px;
  overflow-x: hidden;
}

.wuxia-game {
  max-width: 1920px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 20px;
  min-height: calc(100vh - 40px);
}

/* 头部样式 */
.game-header {
  background: linear-gradient(to right, rgba(20, 40, 40, 0.9), rgba(30, 60, 60, 0.9));
  border-radius: 15px;
  padding: 20px 30px;
  border: 2px solid #8b7355;
  box-shadow: 0 5px 20px rgba(0, 0, 0, 0.5);
  position: relative;
  overflow: hidden;
}

.game-header::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: linear-gradient(to right, #d4af37, #b8860b, #d4af37);
}

.header-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 15px;
}

.chinese-title {
  font-size: 3.2rem;
  color: #d4af37;
  text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.8);
  letter-spacing: 8px;
  font-weight: bold;
  background: linear-gradient(45deg, #d4af37, #ffd700, #d4af37);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.english-title {
  font-size: 1.6rem;
  color: #b8860b;
  letter-spacing: 3px;
  font-style: italic;
}

.subtitle {
  font-size: 1.2rem;
  color: #c9b18a;
  font-style: italic;
  text-align: center;
  max-width: 800px;
  margin: 0 auto;
}

.header-stats {
  display: flex;
  gap: 20px;
  margin-top: 10px;
  flex-wrap: wrap;
  justify-content: center;
}

.stat-badge {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 15px;
  background: rgba(30, 50, 50, 0.7);
  border-radius: 20px;
  border: 1px solid #5a4a30;
}

.badge-icon {
  font-size: 1.2rem;
}

.badge-text {
  font-size: 0.9rem;
  color: #e6d3a7;
}

/* 游戏容器 */
.game-container {
  display: flex;
  gap: 20px;
  flex: 1;
  min-height: 0;
}

/* 左侧面板 */
.left-panel {
  width: 320px;
  display: flex;
  flex-direction: column;
  gap: 20px;
  flex-shrink: 0;
}

/* 玩家卡片 */
.player-card {
  background: rgba(20, 40, 40, 0.9);
  border-radius: 15px;
  padding: 20px;
  border: 1px solid #8b7355;
  box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);
}

.player-header {
  display: flex;
  gap: 20px;
  margin-bottom: 20px;
}

.avatar-container {
  position: relative;
  flex-shrink: 0;
}

.avatar-icon {
  width: 100px;
  height: 100px;
  border-radius: 50%;
  border: 3px solid #8b7355;
  position: relative;
  overflow: hidden;
}

.avatar-icon.wanderer {
  background: linear-gradient(135deg, #2d501f, #5a3921);
}

.avatar-icon.swordsman {
  background: linear-gradient(135deg, #3a5f8f, #2a4a7a);
}

.avatar-icon.master {
  background: linear-gradient(135deg, #d4af37, #b8860b);
}

.avatar-icon.grandmaster {
  background: linear-gradient(135deg, #8b0000, #b22222);
}

.avatar-icon::before {
  content: "⚔";
  font-size: 50px;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

.avatar-icon.master::before,
.avatar-icon.grandmaster::before {
  color: white;
}

.level-badge {
  position: absolute;
  bottom: -5px;
  right: -5px;
  background: #d4af37;
  color: #0c1a1f;
  font-weight: bold;
  padding: 3px 8px;
  border-radius: 10px;
  font-size: 0.8rem;
  border: 2px solid #8b7355;
}

.player-info {
  flex: 1;
}

.player-name {
  font-size: 1.4rem;
  color: #d4af37;
  margin-bottom: 5px;
}

.player-title {
  font-size: 0.9rem;
  color: #b8860b;
  margin-bottom: 15px;
}

.xp-bar {
  margin-top: 10px;
}

.xp-label {
  font-size: 0.8rem;
  color: #c9b18a;
  margin-bottom: 5px;
}

.xp-progress {
  height: 8px;
  background: rgba(0, 0, 0, 0.3);
  border-radius: 4px;
  overflow: hidden;
  margin-bottom: 5px;
}

.xp-fill {
  height: 100%;
  background: linear-gradient(to right, #8b7355, #d4af37);
  border-radius: 4px;
  transition: width 0.5s ease;
}

.xp-text {
  font-size: 0.8rem;
  color: #c9b18a;
  text-align: right;
}

/* 属性网格 */
.attributes-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 12px;
}

.attribute {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px;
  background: rgba(30, 50, 50, 0.6);
  border-radius: 8px;
  border: 1px solid #5a4a30;
}

.attr-icon {
  font-size: 1.2rem;
  width: 30px;
  text-align: center;
}

.attr-info {
  flex: 1;
}

.attr-name {
  font-size: 0.8rem;
  color: #c9b18a;
}

.attr-value {
  font-size: 1.1rem;
  color: #e6d3a7;
  font-weight: bold;
}

.attr-bar {
  width: 60px;
  height: 8px;
  background: rgba(0, 0, 0, 0.3);
  border-radius: 4px;
  overflow: hidden;
}

.bar-fill {
  height: 100%;
  border-radius: 4px;
  transition: width 0.5s ease;
}

.bar-fill.hp {
  background: linear-gradient(to right, #8b0000, #ff4500);
}

.bar-fill.mp {
  background: linear-gradient(to right, #1e3a8a, #3b82f6);
}

/* 装备面板 */
.equipment-panel,
.skills-panel,
.quest-tracker,
.achievements-panel,
.control-panel,
.system-messages {
  background: rgba(20, 40, 40, 0.9);
  border-radius: 15px;
  padding: 20px;
  border: 1px solid #8b7355;
  box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);
}

.panel-title {
  color: #d4af37;
  margin-bottom: 15px;
  font-size: 1.1rem;
  display: flex;
  align-items: center;
  gap: 8px;
}

.equipment-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
}

.equipment-slot {
  padding: 12px;
  background: rgba(30, 50, 50, 0.6);
  border-radius: 8px;
  border: 2px dashed #5a4a30;
  cursor: pointer;
  transition: all 0.3s;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
}

.equipment-slot:hover {
  border-color: #d4af37;
  background: rgba(40, 70, 70, 0.7);
}

.equipment-slot.equipped {
  border-style: solid;
  border-color: #8b7355;
}

.slot-label {
  font-size: 0.8rem;
  color: #c9b18a;
}

.slot-content {
  text-align: center;
}

.equipment-item {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.item-name {
  font-size: 0.9rem;
  color: #e6d3a7;
  font-weight: bold;
}

.item-stats {
  font-size: 0.8rem;
  color: #3b82f6;
}

.empty-slot {
  font-size: 0.8rem;
  color: #8b7355;
  font-style: italic;
}

/* 技能面板 */
.skills-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: 400px;
  overflow-y: auto;
  padding-right: 5px;
}

.skills-list::-webkit-scrollbar {
  width: 6px;
}

.skills-list::-webkit-scrollbar-track {
  background: rgba(0, 0, 0, 0.2);
  border-radius: 3px;
}

.skills-list::-webkit-scrollbar-thumb {
  background: #8b7355;
  border-radius: 3px;
}

.skill-item {
  padding: 12px;
  background: rgba(30, 50, 50, 0.6);
  border-radius: 8px;
  border: 1px solid #5a4a30;
  cursor: pointer;
  transition: all 0.3s;
}

.skill-item:hover {
  background: rgba(40, 70, 70, 0.7);
  border-color: #d4af37;
}

.skill-item.active {
